import React, { useState } from 'react';
import { View, StyleSheet, ScrollView } from 'react-native';
import { 
  Provider as PaperProvider, 
  TextInput, 
  Button, 
  Card, 
  Title, 
  DataTable, 
  ActivityIndicator,
  Appbar,
  Text,
  MD3LightTheme as DefaultTheme
} from 'react-native-paper';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

// --- LOCAL LOGIC IMPORTS ---
import BiwengerClient from './src/logic/BiwengerClient';
import FutbolFantasyScraper from './src/logic/FFScraper';
import LineupOptimizer from './src/logic/Optimizer';

const Stack = createStackNavigator();

const theme = {
  ...DefaultTheme,
  colors: {
    ...DefaultTheme.colors,
    primary: '#1a5c1a',
    secondary: '#fbc02d',
  },
};

// --- SCREENS ---

function LoginScreen({ navigation }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    setLoading(true);
    const client = new BiwengerClient();
    const auth = await client.login(email, password);
    setLoading(false);

    if (auth) {
      navigation.navigate('Dashboard', { auth });
    } else {
      alert('Login failed. Check credentials.');
    }
  };

  return (
    <View style={styles.container}>
      <Card style={styles.card}>
        <Card.Content>
          <Title style={styles.title}>Biwenger Standalone</Title>
          <TextInput
            label="Email"
            value={email}
            onChangeText={setEmail}
            autoCapitalize="none"
            style={styles.input}
          />
          <TextInput
            label="Password"
            value={password}
            onChangeText={setPassword}
            secureTextEntry
            style={styles.input}
          />
          <Button mode="contained" onPress={handleLogin} loading={loading} style={styles.button}>
            Log In
          </Button>
        </Card.Content>
      </Card>
    </View>
  );
}

function Dashboard({ route }) {
  const { auth } = route.params;
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  const runOptimization = async () => {
    setLoading(true);
    try {
      const client = new BiwengerClient(auth.token, auth.user_id, auth.league_id);
      const players = await client.getPlayerData();

      const scraper = new FutbolFantasyScraper();
      const ffProbs = await scraper.getAllLineupData();

      const optimizer = new LineupOptimizer(players, ffProbs);
      const enriched = optimizer.matchPlayers();

      const safe = optimizer.solve(enriched, "safe");
      const risk = optimizer.solve(enriched, "risk");

      setData({ safe, risk, ranking: enriched.sort((a,b) => b.safe_score - a.safe_score) });
    } catch (err) {
      console.error(err);
      alert('Optimization failed.');
    } finally {
      setLoading(false);
    }
  };

  React.useEffect(() => { runOptimization(); }, []);

  if (loading) return (
    <View style={styles.center}>
      <ActivityIndicator size="large" />
      <Text style={{marginTop: 20}}>Scraping & Optimizing on-device...</Text>
    </View>
  );

  return (
    <ScrollView style={styles.scrollView}>
      <Appbar.Header>
        <Appbar.Content title="Dashboard" />
        <Appbar.Action icon="refresh" onPress={runOptimization} />
      </Appbar.Header>

      <Card style={styles.sectionCard}>
        <Card.Content>
          <Title>Safe Lineup ({data?.safe?.formation})</Title>
          {data?.safe?.lineup.map((p, i) => (
            <Text key={i}>{i+1}. {p.name} ({p.pos_name}) - {p.ff_prob}</Text>
          ))}
        </Card.Content>
      </Card>

      <Card style={styles.sectionCard}>
        <Card.Content>
          <Title>Risk-Lover Lineup ({data?.risk?.formation})</Title>
          {data?.risk?.lineup.map((p, i) => (
            <Text key={i}>{i+1}. {p.name} ({p.pos_name}) - {p.ff_prob}</Text>
          ))}
        </Card.Content>
      </Card>

      <Title style={styles.tableTitle}>Player Scorecard</Title>
      <DataTable>
        <DataTable.Header>
          <DataTable.Title>Player</DataTable.Title>
          <DataTable.Title numeric>Safe</DataTable.Title>
          <DataTable.Title numeric>Risk</DataTable.Title>
        </DataTable.Header>
        {data?.ranking.slice(0, 20).map((p, index) => (
          <DataTable.Row key={index}>
            <DataTable.Cell>{p.name}</DataTable.Cell>
            <DataTable.Cell numeric>{p.safe_score}</DataTable.Cell>
            <DataTable.Cell numeric>{p.risk_score}</DataTable.Cell>
          </DataTable.Row>
        ))}
      </DataTable>
    </ScrollView>
  );
}

export default function App() {
  return (
    <PaperProvider theme={theme}>
      <NavigationContainer>
        <Stack.Navigator initialRouteName="Login">
          <Stack.Screen name="Login" component={LoginScreen} options={{ headerShown: false }} />
          <Stack.Screen name="Dashboard" component={Dashboard} />
        </Stack.Navigator>
      </NavigationContainer>
    </PaperProvider>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, justifyContent: 'center', padding: 20, backgroundColor: '#f5f5f5' },
  card: { padding: 10 },
  title: { textAlign: 'center', marginBottom: 20, color: '#1a5c1a' },
  input: { marginBottom: 15 },
  button: { marginTop: 10 },
  center: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  scrollView: { flex: 1, backgroundColor: '#fff' },
  sectionCard: { margin: 10, elevation: 4 },
  tableTitle: { margin: 15, fontSize: 18 },
});
